'use client'

import React from 'react'
import { useState, useEffect } from 'react'

export function Hero() {
  const [isHovering, setIsHovering] = useState(false)
  const [isMounted, setIsMounted] = useState(false)

  useEffect(() => {
    setIsMounted(true)
  }, [])

  return (
    <section className={`relative z-20 flex flex-col items-center justify-center min-h-screen px-4 py-20 ${isMounted ? 'page-fade-in' : 'opacity-0'}`}>
      {/* Profile section */}
      <div className="flex flex-col items-center gap-8 mb-12">
        <div
          className="relative"
          onMouseEnter={() => setIsHovering(true)}
          onMouseLeave={() => setIsHovering(false)}
        >
          <div className={`w-32 h-32 rounded-lg border-2 border-white shadow-lg bg-gray-900 flex items-center justify-center overflow-hidden ${isHovering ? 'shadow-white/50' : 'shadow-white/20'} transition-all duration-300 ${isHovering ? 'animate-profile-tilt' : ''}`}>
            {/* Placeholder avatar - replace with actual image */}
            <div className="w-full h-full bg-gradient-to-br from-gray-800 to-black flex items-center justify-center">
              <span className="text-4xl">♢</span>
            </div>
          </div>
          <div className={`absolute inset-0 rounded-lg border-2 border-white ${isHovering ? 'shadow-lg shadow-white/60 opacity-40' : 'opacity-20'} animate-pulse transition-all duration-300`} />
        </div>

        {/* Title and subtitle */}
        <div className="text-center space-y-4">
          <h1 className="text-6xl md:text-7xl font-light tracking-widest animate-glow-pulse">
            SaunK
          </h1>
          <p className="text-xl md:text-2xl font-light tracking-wider text-gray-400 italic">
            Echoes in the Void
          </p>
        </div>
      </div>
    </section>
  )
}
